class FenwickTree:
    def __init__(self, n):
        self.n    = n
        self.tree = [0] * (n + 1)   # 1-indexed

    def update(self, i, delta):
        """Add delta to position i (1-indexed)."""
        while i <= self.n:
            self.tree[i] += delta
            i += ___________           # move to next responsible index

    def prefix_sum(self, i):
        """Sum of elements at positions 1..i (1-indexed)."""
        total = 0
        while i > 0:
            total += self.tree[i]
            i -= ___________           # peel off lowest set bit
        return total

    def range_sum(self, l, r):
        """Sum of positions l..r (1-indexed)."""
        return self.prefix_sum(r) - self.prefix_sum(l - 1)
